from itertools import combinations
def gen_pairings(points):
    points=tuple(points)
    if not points:
        yield ()
        return
    first=points[0]
    for i in range(1,len(points)):
        second=points[i]
        rest=points[1:i]+points[i+1:]
        for pairing in gen_pairings(rest):
            yield tuple(sorted(((first,second),)+pairing))

def crosses(pair1,pair2,n=6):
    a,b=sorted(pair1)
    c,d=sorted(pair2)
    # Strict interleaving on line/circle with labels 1..n.
    return (a<c<b<d) or (c<a<d<b)

